+export interface FetchPackOptions extends SmartHttpOptions {
+  /** Commit / tag SHAs to fetch. */
+  wants: string[];
+  /** Capabilities to request alongside the first `want`. Default includes `side-band-64k` and `agent`. */
+  capabilities?: string[];
