+function writeTypeSizeHeader(type: number, size: number): Uint8Array {
+  // First byte: type (3 bits, shifted left 4) + low-4 of size + continuation bit
+  const out: number[] = [];
+  let s = size;
+  let byte = ((type & 0x07) << 4) | (s & 0x0f);
+  s >>= 4;
+  if (s > 0) byte |= 0x80;
+  out.push(byte);
+  while (s > 0) {
+    let b = s & 0x7f;
+    s >>= 7;
+    if (s > 0) b |= 0x80;
+    out.push(b);
+  }
+  return new Uint8Array(out);
