+  for (const p of parts) total += p.length;
+  const body = new Uint8Array(total);
+  let pos = 0;
+  for (const p of parts) {
+    body.set(p, pos);
+    pos += p.length;
+  }
+  const trailer = await sha1Bytes(body);
+  const result = new Uint8Array(body.length + 20);
